import{_ as r,c as a,o,ag as d}from"./chunks/framework.XjE0kKti.js";const n="/gatewayweb/docs/assets/hub0005-list.C_9bzQ_C.png",s="/gatewayweb/docs/assets/hub0005-row-menu.BnbLUWux.png",e="/gatewayweb/docs/assets/hub0005-auth-drawer.H4p9XccJ.png",m=JSON.parse('{"title":"角色管理","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0005.md","filePath":"modules/hub0005.md","lastUpdated":1776841524000}'),h={name:"modules/hub0005.md"};function l(i,t,g,b,u,c){return o(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="角色管理" tabindex="-1">角色管理 <a class="header-anchor" href="#角色管理" aria-label="Permalink to &quot;角色管理&quot;">​</a></h1><p>在网关控制台中维护<strong>角色</strong>并为角色授予可访问的菜单/资源，用于构建清晰、可审计的权限体系。本文说明角色的概念、典型操作流程与授权注意事项。</p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><strong>角色</strong>用于将一组权限打包复用，再分配给用户（通常在「用户管理」中完成用户与角色的关联）。在日常运维中，建议遵循：</p><ul><li><strong>最小权限原则</strong>：只授予完成工作所必需的资源。</li><li><strong>角色粒度清晰</strong>：按岗位/职责拆分角色，避免“万能角色”泛滥。</li><li><strong>内置与自定义分离</strong>：内置角色通常用于系统保底能力；业务扩展使用自定义角色更易维护。</li></ul><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>系统设置</strong> → <strong>角色管理</strong>。</p><hr><h2 id="页面布局" tabindex="-1">页面布局 <a class="header-anchor" href="#页面布局" aria-label="Permalink to &quot;页面布局&quot;">​</a></h2><p>页面分为上下两块：</p><ol><li><strong>筛选与操作区</strong>：按角色名称、状态、类型筛选；提供 <strong>新增</strong>、<strong>编辑</strong>、<strong>删除</strong> 等主操作。</li><li><strong>角色列表</strong>：分页展示角色信息，支持复选与右键快捷菜单，并可从行菜单进入 <strong>角色授权</strong>。</li></ol><p><img src="'+n+'" alt="角色管理：列表"></p><hr><h2 id="查找角色" tabindex="-1">查找角色 <a class="header-anchor" href="#查找角色" aria-label="Permalink to &quot;查找角色&quot;">​</a></h2><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>角色名称</td><td>按角色名称检索（占位提示为「请输入角色名称」）。</td></tr><tr><td>状态</td><td>全部、启用或禁用。</td></tr><tr><td>类型</td><td>全部、内置或自定义。</td></tr></tbody></table><p>设置条件后点击 <strong>查询</strong>；需要回到默认视图时使用 <strong>重置</strong>（会清空筛选并恢复分页初始状态）。</p><hr><h2 id="列表字段说明" tabindex="-1">列表字段说明 <a class="header-anchor" href="#列表字段说明" aria-label="Permalink to &quot;列表字段说明&quot;">​</a></h2><p>常见列包括：<strong>角色 ID</strong>、<strong>角色名称</strong>、<strong>角色描述</strong>、<strong>状态</strong>（启用/禁用）、<strong>类型</strong>（内置/自定义）、<strong>活动标记</strong>（活动/非活动）、创建/修改时间与人员、备注等（具体列以版本与配置为准）。</p><ul><li><strong>复选与目标行规则</strong>：工具栏的 <strong>编辑/删除</strong> 需要目标行；通常遵循「优先勾选行，否则使用当前点击的行」。若未选择任何行，界面会提示先选择角色。</li><li><strong>分页</strong>：翻页时会保留当前筛选条件重新查询，避免跨页后条件丢失。</li></ul><hr><h2 id="工具栏操作" tabindex="-1">工具栏操作 <a class="header-anchor" href="#工具栏操作" aria-label="Permalink to &quot;工具栏操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>用途与说明</th></tr></thead><tbody><tr><td><strong>新增</strong></td><td>新建一个角色，用于后续授权与分配给用户。</td></tr><tr><td><strong>编辑</strong></td><td>修改所选角色的基本信息（如名称、描述、状态等）。</td></tr><tr><td><strong>删除</strong></td><td>二次确认后删除角色；删除不可恢复。若删除后当前页为空且不是第一页，列表会自动回到上一页并刷新。</td></tr></tbody></table><hr><h2 id="行右键菜单" tabindex="-1">行右键菜单 <a class="header-anchor" href="#行右键菜单" aria-label="Permalink to &quot;行右键菜单&quot;">​</a></h2><p>在某一角色行上右键，可以对当前行直接执行常用动作：</p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>查看详情</strong></td><td>只读查看角色字段，用于核对信息。</td></tr><tr><td><strong>编辑</strong></td><td>打开编辑对话框，作用于当前行。</td></tr><tr><td><strong>删除</strong></td><td>删除当前行角色（需二次确认）。</td></tr><tr><td><strong>角色授权</strong></td><td>打开授权抽屉，维护该角色拥有的菜单/资源。</td></tr></tbody></table><p><img src="'+s+'" alt="角色管理：行右键菜单"></p><hr><h2 id="新增、编辑与查看" tabindex="-1">新增、编辑与查看 <a class="header-anchor" href="#新增、编辑与查看" aria-label="Permalink to &quot;新增、编辑与查看&quot;">​</a></h2><p>三者共用同一套表单，通过标题区分：<strong>新增角色</strong>、<strong>编辑角色</strong>、<strong>查看角色详情</strong>。</p><h3 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>角色ID</td><td>角色的唯一标识。</td></tr><tr><td>角色名称</td><td>建议使用可读性强的命名（如“运维只读”“网关管理员”等）。</td></tr><tr><td>角色描述</td><td>说明该角色的使用场景与边界，便于审计。</td></tr><tr><td>角色状态</td><td>启用/禁用。禁用后通常不应再为用户授予该角色（实际生效策略以后端权限模型为准）。</td></tr><tr><td>类型（内置标记）</td><td>内置/自定义。内置角色一般建议谨慎修改与删除。</td></tr><tr><td>数据权限范围</td><td>用于描述数据级权限范围；界面提示为 JSON 格式。若组织未启用数据级权限，可保持为空或按规范填写。</td></tr></tbody></table><h3 id="其他信息" tabindex="-1">其他信息 <a class="header-anchor" href="#其他信息" aria-label="Permalink to &quot;其他信息&quot;">​</a></h3><p>创建时间、创建人、修改时间、修改人、版本号等为审计字段，通常只读展示。</p><hr><h2 id="角色授权-资源-菜单" tabindex="-1">角色授权（资源/菜单） <a class="header-anchor" href="#角色授权-资源-菜单" aria-label="Permalink to &quot;角色授权（资源/菜单）&quot;">​</a></h2><p>从行菜单进入 <strong>角色授权</strong> 会打开抽屉，在树形资源列表中为角色勾选可访问项：</p><ul><li><strong>搜索</strong>：在抽屉顶部输入关键词，快速定位资源名称。</li><li><strong>树形勾选</strong>：支持级联选择；建议按业务模块逐层展开配置。</li><li><strong>保存</strong>：保存后角色权限立即更新或在一定缓存周期后生效（以部署策略为准）。</li></ul><p><img src="'+e+'" alt="角色授权：资源树抽屉"></p><h3 id="授权建议" tabindex="-1">授权建议 <a class="header-anchor" href="#授权建议" aria-label="Permalink to &quot;授权建议&quot;">​</a></h3><ul><li><strong>先建角色，再授权</strong>：角色是权限容器，先稳定角色边界再给用户分配更可控。</li><li><strong>避免给内置角色“叠加业务权限”</strong>：业务权限变化频繁，放在自定义角色更易回滚与审计。</li><li><strong>按最小权限逐步放开</strong>：先满足“能用”，再按需求补齐；比事后回收权限成本更低。</li></ul><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因与处理</th></tr></thead><tbody><tr><td>提示先选择角色</td><td>工具栏操作依赖目标行：请先勾选一行，或单击一行使其成为当前行。</td></tr><tr><td>找不到要授权的资源</td><td>检查是否有资源树数据权限；或资源是否在「权限资源管理」中已登记并同步。</td></tr><tr><td>授权保存后菜单未变化</td><td>可能需要重新登录或等待缓存失效；也可能用户未分配该角色（需在「用户管理」中为用户授权角色）。</td></tr></tbody></table>',47)])])}const _=r(h,[["render",l]]);export{m as __pageData,_ as default};
